                        case 1:
                            PaintAddImageAsParentRotated(
                                session, direction, session.TrackColours.WithIndex((SPR_TRACKS_SPINNING_TRACK_VERTICAL + 9)),
                                { 0, 0, height }, { { 24, 6, height + 8 }, { 2, 20, 31 } });
