    // adding 1 Turn tile curve to the track
    static void SpinningRCTrackLeftQuarterTurn1(
        PaintSession& session, const Ride& ride, uint8_t trackSequence, uint8_t direction, int32_t height,
        const TrackElement& trackElement, SupportType supportType)
    {
        switch (direction)
        {
            case 0:
                PaintAddImageAsParentRotated(
                    session, direction, session.TrackColours.WithIndex(SPR_TRACKS_SPINNING_TRACK_CURVE_VERY_SMALL + 0),
                    { 0, 0, height }, { { 6, 2, height }, { 26, 24, 2 } });
                break;
            case 1:
                PaintAddImageAsParentRotated(
                    session, direction, session.TrackColours.WithIndex(SPR_TRACKS_SPINNING_TRACK_CURVE_VERY_SMALL + 1),
                    { 0, 0, height }, { 26, 26, 2 });
                break;
            case 2:
                PaintAddImageAsParentRotated(
                    session, direction, session.TrackColours.WithIndex(SPR_TRACKS_SPINNING_TRACK_CURVE_VERY_SMALL + 2),
                    { 0, 0, height }, { { 2, 6, height }, { 24, 26, 2 } });
                break;
            case 3:
                PaintAddImageAsParentRotated(
                    session, direction, session.TrackColours.WithIndex(SPR_TRACKS_SPINNING_TRACK_CURVE_VERY_SMALL + 3),
                    { 0, 0, height }, { { 6, 6, height }, { 24, 24, 2 } });
                break;
        }

        TrackPaintUtilLeftQuarterTurn1TileTunnel(
            session, TunnelGroup::Square, direction, height, -8, TunnelSubType::SlopeStart, +56, TunnelSubType::SlopeEnd);
        MetalASupportsPaintSetup(session, kSupportType, MetalSupportPlace::centre, 8, height, session.SupportColours);
        PaintUtilSetSegmentSupportHeight(
            session,
            PaintUtilRotateSegments(
                EnumsToFlags(PaintSegment::left, PaintSegment::centre, PaintSegment::topLeft, PaintSegment::bottomLeft),
                direction),
            0xFFFF, 0);
        PaintUtilSetGeneralSupportHeight(session, height + 32);
    }

